1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PRICE = 60;
16	
17	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];
18	
19	const sumItemPremiums = (items: any[]): number =>
20	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
21	
22	const groupByType = (items: any[]): Record<string, any[]> =>
23	  items.reduce((groups, item) => {
24	    (groups[item.type] ||= []).push(item);
25	    return groups;
26	  }, {} as Record<string, any[]>);
27	
28	const calculateBasePremium = (items: any[]): number => {
29	  const groups = groupByType(items);
30	  let total = 0;
31	  for (const type in groups) {
32	    const group = groups[type];
33	    if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
34	      total += BLOCK_PRICE;
35	    } else {
36	      total += sumItemPremiums(group);
37	    }
38	  }
39	  return total;
40	};
41	
42	const addPercent = (amount: number, percent: number): number =>
43	  amount + (amount * percent) / 100;
44	
45	const quotePremium = (items: any[]): number => {
46	  const base = calculateBasePremium(items);
47	  const withSurcharge = addPercent(base, FIRST_INSURANCE_SURCHARGE_PERCENT);
48	  return Math.ceil(withSurcharge + PROCESSING_FEE);
49	};
50	
51	export const runScenario = (scenario: any): unknown => {
52	  const items = scenario.steps[0].items;
53	  return { results: [{ premium: quotePremium(items) }] };
54	};
